INSERT INTO public.learning_paths (id, organization_id, name, description, is_active)
VALUES
  ('e2000000-0000-4000-8000-000000000000', NULL, 'リーダー成長ロードマップ（主任前夜→経営者）', 'あわい屋ZEROSの教育コンテンツを、役割の成長段階に沿って学ぶ縦断パス。L0.7「主任になる前夜」から、L1「新任主任」・L2「管理者」・L3「経営者」へと、立場が上がるごとに必要になる視点を順番に積み上げる全21コース。', true),
  ('e4000000-0000-4000-8000-000000000000', NULL, '医療・介護 必須研修ロードマップ', '医療・介護の現場で毎年求められる必須研修を、全職種共通テーマ→医療職向け→介護職向けの順に学ぶパス。感染対策・虐待防止・身体拘束・看取り・医療安全など20本を3コースに束ねた必須カリキュラム。', true)
