-- あわい屋ZEROS  ロードマップ（学習パス）投入 seed  2026-06-17
-- learning_paths（Global / organization_id=NULL）＋ learning_path_courses
-- 冪等: 固定UUID + ON CONFLICT。再実行で重複しません。
-- 実行: Supabase ダッシュボード > SQL Editor で Run
-- =====================================================================

ON CONFLICT (id) DO UPDATE
  SET name = EXCLUDED.name, description = EXCLUDED.description, is_active = EXCLUDED.is_active;

ON CONFLICT (learning_path_id, course_id) DO UPDATE
  SET sort_order = EXCLUDED.sort_order;

